head.script:
// 전역변수
scwin.login = $c.data.getMemInfo();
scwin.privAdmin = scwin.login.privAdmin;
scwin.sysAdminYn = scwin.login.sysAdminYn;
scwin.vUserHomeClsCd = scwin.login.userHomeClsCd;
scwin.vCoCd = scwin.login.coCd;
scwin.vLoginCoClsCd = scwin.login.coClsCd;
scwin.isSubCompany = false;
scwin.vAuth = "N";  //신고옵션 선택 권한   
scwin.isRetrieve = false;
scwin.vEmpNo = $c.data.getMemInfo("empNo");
scwin.deptCd = $c.data.getMemInfo("acctDeptCd");
scwin.deptNm = $c.data.getMemInfo("acctDeptNm");
scwin.txtCoClsCd;
scwin.isFirst = true;


scwin.onpageload = function () {

};

scwin.onUdcCompleted = async function () {

    const codeOptions = [
        { grpCd: "FI115", compID: "acb_payGbn,gr_list:payGbn" },
        { grpCd: "OP160", compID: "gr_list:occptypeCd" },
        { grpCd: "OP161", compID: "gr_list:dtlOccptypeCd" }
    ];
    $c.data.setCommonCode(codeOptions);

    dma_search2.set("coCd", scwin.vCoCd);
    // f_HeaderCreate();

    scwin.f_FieldClear();

    scwin.getMaxCloseYm(); //마감년월 가져오기

    // 동원로엑스 - HR팀, 재경팀은 모든 귀속부서 조회가능
    // 넥스트로 - 기획관리팀(넥스트로) 모든 귀속부서 조회가능
    if (scwin.deptCd == "00006" || scwin.deptCd == "00009" || scwin.deptCd == "01387") {
        $c.gus.cfEnableObjects([ed_acctDeptCd, ed_acctDeptNm, btn_lobran]);
        ed_acctDeptCd.focus();
    } else {
        $c.gus.cfDisableObjects([ed_acctDeptCd, ed_acctDeptNm, btn_lobran]);
    }
    scwin.f_setCompanyInfo();

    ica_payYm.focus();
    $c.gus.cfDisableBtnOnly([btn_SlipCreate, btn_SlipDel, btn_Save]);
    // gr_list.TitleHeight = "30";

}

// 전월 마감여부 
scwin.getMaxCloseYm = function () {
    $c.sbm.execute(sbm_getMaxCloseYm);
}

scwin.f_FieldClear = function () {
    ica_payYm.setValue(WebSquare.date.getCurrentServerDate().substring(0, 6));
    ica_regDt.setValue(WebSquare.date.getCurrentServerDate());

    $p.setTimeout(function () {
        ed_acctDeptCd.setValue(scwin.deptCd);
        ed_acctDeptNm.setValue(scwin.deptNm);
    }, { "delay": 50 });

    chk_lowerDeptIncluYn.setValue("");

    ed_staffNo.setValue("");
    ed_staffNm.setValue("");
    acb_payGbn.setSelectedIndex(0);
}

scwin.f_Retrieve = async function () {
    if (!await $c.gus.cfValidate([searchCondition])) {
        return;
    }

    if (chk_lowerDeptIncluYn.getValue() == "1") {
        dma_search.set("lowerDeptIncluYn", 1);
    } else {
        dma_search.set("lowerDeptIncluYn", 0);
    }

    dma_search.set("payYm", ica_payYm.getValue());
    dma_search.set("payGbn", acb_payGbn.getValue());
    dma_search.set("regDt", ica_regDt.getValue());
    // dma_search.set("acctDeptCd",acb_acctDeptCd.getValue());

    $c.sbm.execute(sbm_search);
}

//전표생성
scwin.f_Save = async function () {

    var cnt = 0;

    if (!await $c.gus.cfValidate([ica_regDt])) {
        return false;
    }

    for (var i = 0; i < ds_list.getTotalRow(); i++) {
        if (ds_list.getCellData(i, "chk") == "1") {
            cnt++;
            if (ds_list.getCellData(i, "slipNo") != "") {
                await $c.gus.cfAlertMsg("[" + ds_list.getCellData(i, "staffNm") + "] 이미 전표생성된 내역은 선택 불가합니다.");
                return;
            } else {
                if (ds_list.getCellData(i, "workTax") < 1000) { 		//소득세 천원 미만인 경우
                    if (ds_list.getCellData(i, "taxchk") == 1) {	//소액부징수 여부 체크
                        ds_list.setCellData(i, "workTax", 0);
                        ds_list.setCellData(i, "localTax", 0);
                    } else {
                        await $c.gus.cfAlertMsg("[" + ds_list.getCellData(i, "staffNm") + "] 소액부 징수 대상입니다. \n소액부징수여부 미체크 시 소득세/지방소득세가 생성됩니다.");
                    }
                }
            }
        }
    }

    if (cnt == 0) {
        await $c.gus.cfAlertMsg("선택한 내역이 존재하지 않습니다.");
        return;
    }

    if (await $c.win.confirm("전표를 생성하시겠습니까?") == true) {
        $c.sbm.execute(sbm_save);
    }
}

//전표삭제
scwin.f_Delete = async function () {

    var cnt = 0;

    for (var i = 0; i < ds_list.getTotalRow(); i++) {
        if (ds_list.getCellData(i, "chk") == 1) {
            cnt++;
            if (ds_list.getCellData(i, "slipNo") == "") {
                await $c.gus.cfAlertMsg("[" + ds_list.getCellData(i, "staffNm") + "] 전표생성된 내역이 없습니다. 전표삭제 불가합니다.");
                return;
            }
        }
    }

    if (cnt == 0) {
        await $c.gus.cfAlertMsg("선택한 내역이 존재하지 않습니다.");
        return;
    }

    if (await $c.win.confirm("전표를 삭제하시겠습니까?") == true) {
        $c.sbm.execute(sbm_delete);
    }
}

// 저장 (연차수당, 공제내역, 보소지급기초일수 UPDATE)
scwin.f_Update = async function () {

    var cnt = 0;

    for (var i = 0; i < ds_list.getTotalRow(); i++) {
        if (ds_list.getCellData(i, "chk") == 1) {
            cnt++;
            if (ds_list.getCellData(i, "slipNo") != "") {
                await $c.gus.cfAlertMsg("[" + ds_list.getCellData(i, "staffNm") + "] 이미 전표생성된 내역은 수정할 수 없습니다.");
                return;
            }
        }
    }

    if (cnt == 0) {
        await $c.gus.cfAlertMsg("선택한 내역이 존재하지 않습니다.");
        return;
    }

    if (ds_list.getModifiedIndex() == 0) {
        await $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return;
    }


    if (await $c.win.confirm("저장 하시겠습니까?") == true) {
        $c.sbm.execute(sbm_update);
    }
}

// function Parameter : inObj : 코드값, pairObj : 코드명, disGubun : 구분, isCode : 코드구분(코드, 명칭)
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);
    // inObj가 코드 필드일 경우 팝업

    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
        // inObj가 코드명 필드일 경우 팝업
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
}

// function Parameter : disGubun : 구분, pCode : 코드, pName : 코드명, pClose : 창여부, pAllSearch : 전체허용여부
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList;  // 공통POP-UP -> 요청화면 
    switch (disGubun) {
        case 1:	// 귀속부서
            var param = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd;
            rtnList = udc_retrieveAcctDept.cfCommonPopUp(scwin.udc_retrieveAcctDept_callBack
                , pCode
                , pName
                , pClose
                , null
                , null
                , null
                , null
                , param
                , null
                , null
                , null
                , null);

            break;
        case 2: // 일용직 사원정보
            var param = "," + ed_coCd.getValue();
            rtnList = udc_staffList.cfCommonPopUp(scwin.udc_staffList_callBack    // XML상의 SELECT ID  
                , pCode                  			// 화면에서의 ??? Code Element의  Value
                , pName                  			// 화면에서의 ??? Name Element의  Value
                , pClose                 			// 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                , null                   			// 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                , null                   			// Title순서  
                , null                   			// 보여주는 각 컬럼들의 폭    
                , null                   			// 컬럼중에서 숨기는    컬럼 지정   
                , "1"                   				// SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                , null                   			// POP-UP뛰을때 원도우의   사용자 정의  폭
                , null                   			// POP-UP뛰을때 우도우의   사용자 정의  높이  
                , param                   			// 윈도우 위치 Y좌표   
                , null                   			// 윈도우 위치 X좌표
                , null                   			// 중복체크여부   ("F")
                , pAllSearch                 		// 전체검색허용여부 ("F")
                , "인원,사번,인원명"                 // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;
    }
}

scwin.udc_retrieveAcctDept_callBack = function (rtnList) {
    // $c.gus.cfSetReturnValue(rtnList, ed_acctDeptCd, ed_acctDeptNm);

    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;

        ed_acctDeptCd.setValue(rtnList[0]);   // 코드
        ed_acctDeptNm.setValue(rtnList[1]);   // 회사명
        ed_acctDeptCd.options.hidVal = rtnList[0];
    } else {
        ed_acctDeptCd.setValue("");
        ed_acctDeptNm.setValue("");
        ed_acctDeptCd.options.hidVal = "";
    }

}

scwin.udc_staffList_callBack = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_staffNo, ed_staffNm);
}

scwin.f_toExcel1 = function () {

    let options = {
        fileName: "일용직급여내역",    // + ".xls",
        sheetName: "일용직급여내역",
        type: 1,
        headerColor: "#eeeeee" //"#E8E8E8", //연한회색 #33CCCC
    };
    $c.data.downloadGridViewExcel(gr_list, options, "");
}

//급여생성
scwin.f_DayLaborersAllowancePopUp = async function () {

    let data = {
        prov: dma_search
        , UserDeptCd: $c.data.getMemInfo("acctDeptCd") // getAllArray
        , UserDeptNm: $c.data.getMemInfo("acctDeptNm") // 전표일자 (작성일자)
        , UserCoCd: ed_coCd.getValue()               // 총금액
        , UserCoNm: ed_coNm.getValue()               // 관련사건저장순번
        , UserCoClsCd: scwin.txtCoClsCd                 // 상위회계부서코드
        , PayYm: ica_payYm.getValue()             // 팝업모드 (신규 추가)
    }

    let win_url = "/ui/ac/fi/taxbiz/tempjob/fi_405_01_03p.xml";

    let opts = {
        id: "smpPop"
        , popupName: "일용직급여생성"
        , modal: true
        , type: "browserPopup"
        , width: 600
        , height: 300
        , title: "일용직급여생성"
    };

    let returnValue = await $c.win.openPopup(win_url, opts, data);

    scwin.f_Retrieve();	// 다시 조회
}

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function (e) {

    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }

    ed_coCd.setValue(scwin.vCoCd);
    scwin.f_PopUpCompanyInfo('T');
}

scwin.f_PopUpCompanyInfo = function (pWinCloseTF) {
    scwin.pWinClose = pWinCloseTF;
    var rtnList = udc_companyInfo.cfCommonPopUp(scwin.udc_coCd_callBackFunc
        , ed_coCd.getValue(), ed_coNm.getValue()
        , pWinCloseTF, null, null, null, null
        , null, null, null, null, null);
}

scwin.udc_coCd_callBackFunc = function (rtnList) {
    // SET	 
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;

        ed_coCd.setValue(rtnList[0]);	// 코드
        ed_coNm.setValue(rtnList[5]); // 회사명 
        ed_coCd.options.hidVal = rtnList[0];  // 히든값
        scwin.txtCoClsCd = rtnList[1];	// 회사구분  
    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        ed_coCd.options.hidVal = "";
        scwin.txtCoClsCd = "";
    }

    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {  	// 자회사 회계 시스템 
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }

    if(scwin.isFirst == true){
        if ('T' == scwin.privAdmin || !scwin.isSubCompany) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
            $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
        } else {
            $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
        }

        scwin.isFirst = false;
    }

}

scwin.udc_companyInfo_onclickEvent = function (e) {
    scwin.f_PopUpCompanyInfo('F');
};

scwin.udc_retrieveAcctDept_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_acctDeptCd.getValue(), ed_acctDeptNm.getValue(), 'F', 'T')
};


scwin.udc_retrieveAcctDept_onviewchangeNameEvent = function (info) {
    ed_acctDeptCd.setValue("");
    if (!$c.gus.cfIsNull(ed_acctDeptNm.getValue())) {
        scwin.f_openCommonPopUp(1, ed_acctDeptCd.getValue(), ed_acctDeptNm.getValue(), 'F', 'T')
    };
};

scwin.udc_retrieveAcctDept_onblurCodeEvent = function (e) {
    ed_acctDeptNm.setValue("");
    if (!$c.gus.cfIsNull(ed_acctDeptCd.getValue())) {
        scwin.f_openCommonPopUp(1, ed_acctDeptCd.getValue(), ed_acctDeptNm.getValue(), 'T', 'T')
    };
};

scwin.udc_staffList_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_staffNo, ed_staffNm, 2);
};

scwin.udc_staffList_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_staffNo.getValue(), ed_staffNm.getValue(), 'F', 'T');
};

scwin.udc_staffList_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_staffNm, ed_staffNo, 2, false)
};

scwin.sbm_search_submitdone = async function (e) {
    var rowCnt = ds_list.getTotalRow();
    ed_totalRow.setValue(rowCnt);

    if (rowCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        $c.gus.cfDisableBtnOnly([btn_SlipCreate, btn_SlipDel, btn_Save]);
        return;
    }
    $c.gus.cfEnableBtnOnly([btn_SlipCreate, btn_SlipDel, btn_Save]);

    for (let i = 0; i < rowCnt; i++) {

        ds_list.setCellData(i, "totPayAmt1", Number(ds_list.getCellData(i,"totPayAmt")) + Number(ds_list.getCellData(i,"etcDedtAmt")));

        if (ds_list.getCellData(i, "slipNo") == "") {
            if (ds_list.getCellData(i, "chk") == "1") {
                gr_list.setReadOnly("cell", i, "pensionDedtAmt", false);
                gr_list.setReadOnly("cell", i, "healthDedtAmt", false);
                gr_list.setReadOnly("cell", i, "unempDedtAmt", false);
                gr_list.setReadOnly("cell", i, "workTax", false);
                gr_list.setReadOnly("cell", i, "localTax", false);
                gr_list.setReadOnly("cell", i, "taxchk", false);
                gr_list.setReadOnly("cell", i, "payBasicDay", false);
            } else {
                gr_list.setReadOnly("cell", i, "pensionDedtAmt", true);
                gr_list.setReadOnly("cell", i, "healthDedtAmt", true);
                gr_list.setReadOnly("cell", i, "unempDedtAmt", true);
                gr_list.setReadOnly("cell", i, "workTax", true);
                gr_list.setReadOnly("cell", i, "localTax", true);
                gr_list.setReadOnly("cell", i, "taxchk", true);
                gr_list.setReadOnly("cell", i, "payBasicDay", true);
            }
        } else {
            gr_list.setReadOnly("cell", i, "pensionDedtAmt", true);
            gr_list.setReadOnly("cell", i, "healthDedtAmt", true);
            gr_list.setReadOnly("cell", i, "unempDedtAmt", true);
            gr_list.setReadOnly("cell", i, "workTax", true);
            gr_list.setReadOnly("cell", i, "localTax", true);
            gr_list.setReadOnly("cell", i, "taxchk", true);
            gr_list.setReadOnly("cell", i, "payBasicDay", true);
        }
    }
};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);  //"성공적으로 저장하였습니다."
        scwin.f_Retrieve();

        var position = ds_slipNo.getRowPosition();
        if (position == "" || position == null) {
            position = 0;
        }

        if (ds_slipNo.getCellData(position, "slipNo") != "") {
            $c.gus.cfShowSlipInfo(ds_slipNo.getCellData(position, "slipNo"));
        }
    }
};

scwin.sbm_delete_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        await $c.gus.cfAlertMsg(MSG_CM_INF_004);  //"성공적으로 삭제하였습니다."
        scwin.f_Retrieve();
    }
};

scwin.sbm_update_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);  //"성공적으로 삭제하였습니다."
        scwin.f_Retrieve();
    }
};

scwin.gr_list_oncellclick = function (rowIndex, columnIndex, columnId) {
    var Colid = gr_list.getColumnID(columnIndex)
    // 전표번호가 존재하는 행 선택시 동일한 전표번호 행 모두 선택
    if (Colid == "chk") {
        if (!$c.gus.cfIsNull(ds_list.getCellData(rowIndex, "slipNo"))) {
            for (i = 0; i < ds_list.getTotalRow(); i++) {
                if (ds_list.getCellData(rowIndex, "slipNo") == ds_list.getCellData(i, "slipNo")) {
                    ds_list.setCellData(i, "chk", ds_list.getCellData(rowIndex, "chk"));
                }
            }
        }
    }

    // 전표번호 선택 시
    if (Colid == "slipNo" && !$c.gus.cfIsNull(ds_list.getCellData(rowIndex, "slipNo"))) {
        $c.gus.cfShowSlipInfo(ds_list.getCellData(ds_list.getRowPosition(), "slipNo"));
    }
};

scwin.sbm_getMaxCloseYm_submitdone = function (e) {
    var thisYm = WebSquare.date.getCurrentServerDate(); // 오늘일자 가져오기
    //최소 미마감월이 당월이 아닐때
    if (ds_getMaxCloseYm.getCellData(0, "closeYm") != thisYm.substr(0, 6)) {
        var closeYm = ds_getMaxCloseYm.getCellData(0, "closeYm");
        var firstDay = closeYm.substr(0, 4) + "/" + closeYm.substr(4, 2) + "/" + "01";  // 1일
        let lastDD = $c.date.getLastDateOfMonth(closeYm);
        // var lastDay =  closeYm.substr(0,4)+"/"+closeYm.substr(4,2)+"/" + new Date(closeYm.substr(0,4),closeYm.substr(4,2),0).getDate(); // 마지막날
        ica_regDt.setValue(closeYm + lastDD);
    } else {
