scwin.customFormat = function (data, formattedData, rowIndex, colIndex) {
    var value;

    value = Number(ds_list.getCellData(rowIndex, "totPayAmt")) - Number(ds_list.getCellData(rowIndex, "taxFreeAmt"));
    return $c.num.formatNumber(value);
}

